on conflict (id) do update set
  event_id = excluded.event_id,
  match_id = excluded.match_id,
  poll_type = excluded.poll_type,
  title = excluded.title,
  opens_at = excluded.opens_at,
  closes_at = excluded.closes_at,
  archived_at = coalesce(public.polls.archived_at, excluded.archived_at),
  winner_choice_id = coalesce(public.polls.winner_choice_id, excluded.winner_choice_id);

-- Knockout matches cannot end in a draw (extra time / pens) — no draw choice
delete from public.poll_choices pc
using public.polls p
join public.matches m on m.id = p.match_id
where pc.poll_id = p.id
  and pc.id = 'draw'
  and m.stage <> 'group'
  and p.event_id = 'wc-2026';

on conflict (poll_id, id) do update set
  label = excluded.label,
  meta = excluded.meta,
  sort_order = excluded.sort_order;

commit;

-- Verification
select 'events' as entity, count(*)::text as n from public.events where id = 'wc-2026'
union all select 'matches', count(*)::text from public.matches where event_id = 'wc-2026'
union all select 'polls', count(*)::text from public.polls where event_id = 'wc-2026'
union all select 'poll_choices', count(*)::text from public.poll_choices pc
  join public.polls p on p.id = pc.poll_id where p.event_id = 'wc-2026'
union all select 'draw_choices_group_only',
  case when count(*) = 0 then 'ok' else count(*)::text || ' draw in knockout' end
  from public.poll_choices pc
  join public.polls p on p.id = pc.poll_id
  join public.matches m on m.id = p.match_id
  where p.event_id = 'wc-2026' and pc.id = 'draw' and m.stage <> 'group'
union all select 'featured', slug from public.events where is_featured = true;
